import anthropic

client = anthropic.Client()

# Count tokens in a message
total_tokens = client.count_tokens([
    {
        "role": "user",
        "content": "Sample text to count tokens"
    }
])

print(f"Token count: {total_tokens}")

{
  "model": "MODEL_ID",
